t!(nobody.check(Operation::Admin).is_err());\\n449\\t    }\\n450\\t\\n451\\t    #[test]\\n452\\t    fn write_denied_error_is_descriptive() {\\n453\\t        let reader = CallerIdentity::new(\\\"charlie\\\", Role::Read);\\n454\\t        let err = reader\\n455\\t            .check(Operation::Write)\\n456\\t            .expect_err(\\\"read role should not be allowed to write\\\");\\n457\\t        let msg = err.to_string();\\n458\\t        assert!(msg.contains(\\\"permission denied\\\"), \\\"msg: {msg}\\\");\\n459\\t        assert!(msg.contains(\\\"read\\\"), \\\"msg: {msg}\\\");\\n460\\t        assert!(msg.contains(\\\"write\\\"), \\\"msg: {msg}\\\");\\n461\\t    }\\n462\\t\\n463\\t    // ── Field-level masking tests (US-046) ──────────────────────────────\\n464\\t\\n465\\t    #[test]\\n466\\t    fn admin_sees_all_fields() {\\n467\\t        let admin = CallerIdentity::new(\\\"admin\\\", Role::Admin);\\n468\\t        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"salary\\\": 100000});\\n469\\t        let policies = vec![MaskPolicy {\\n470\\t            field: \\\"salary\\\".into(),\\n471\\t            min_role: Role::Admin,\\n472\\t        }];\\n473\\t        admin.apply_masks(\u0026mut data, \u0026policies);\\n474\\t        assert!(data.get(\\\"salary\\\").is_some(), \\\"admin should see salary\\\");\\n475\\t    }\\n476\\t\\n477\\t    #[test]\\n478\\t    fn reader_cannot_see_admin_only_fields() {\\n479\\t        let reader = CallerIdentity::new(\\\"bob\\\", Role::Read);\\n480\\t        let mut data =\\n481\\t            serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"salary\\\": 100000, \\\"email\\\": \\\"alice@co.com\\\"});\\n482\\t        let policies = vec![MaskPolicy {\\n483\\t            field: \\\"salary\\\".into(),\\n484\\t            min_role: Role::Admin,\\n485\\t        }];\\n486\\t        reader.apply_masks(\u0026mut data, \u0026policies);\\n487\\t        assert!(data.get(\\\"salary\\\").is_none(), \\\"reader should not see salary\\\"