	}
	endedAt := time.Time{}
	if e.Duration > 0 {
		endedAt = e.Timestamp.Add(time.Duration(e.Duration) * time.Millisecond).UTC()
	}
	totalTokens := e.TotalTokens
	if totalTokens == 0 {
		totalTokens = e.Tokens
	}
	return SessionIndexEntry{
		ID:              e.ID,
		ProjectID:       ProjectIDForPath(projectRoot),
		BeadID:          beadID,
