func sessionIndexEntryInRange(entry SessionIndexEntry, q SessionIndexQuery) bool {
	if q.StartedAfter != nil && entry.StartedAt.Before(*q.StartedAfter) {
		return false
	}
	if q.StartedBefore != nil && !entry.StartedAt.Before(*q.StartedBefore) {
		return false
	}
	return true
}

func sessionShardIntersects(name string, q SessionIndexQuery) bool {
	month, ok := sessionShardMonth(name)
	if !ok {
		return false
	}
	next := month.AddDate(0, 1, 0)
	if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
		now := time.Now().UTC()
		current := time.Date(now.Year(), now.Month(), 1, 0, 0, 0, 0, time.UTC)
		previous := current.AddDate(0, -1, 0)
		return month.Equal(current) || month.Equal(previous)
	}
	if q.StartedAfter != nil && !next.After(*q.StartedAfter) {
		return false
	}
	if q.StartedBefore != nil && !month.Before(*q.StartedBefore) {
	if q.StartedBefore != nil && !month.Before(*q.StartedBefore) {
		return false
	}
	return true
}

func sessionShardMonth(name string) (time.Time, bool) {
	if len(name) != len("sessions-2006-01.jsonl") {
		return time.Time{}, false
	}
	month, err := time.Parse("2006-01", strings.TrimSuffix(strings.TrimPrefix(name, "sessions-"), ".jsonl"))
	if err != nil {
		return time.Time{}, false
	}
	return month.UTC(), true
}

func firstNonEmpty(values ...string) string {
	for _, value := range values {
		if strings.TrimSpace(value) != "" {
			return value
		}
	}
	return ""
}

func existingSessionIndexIDs(logDir string) (map[string]struct{}, error) {
	ids := map[string]struct{}{}
	files, err := SessionIndexShardFiles(logDir, SessionIndexQuery{})
	if err != nil {
		return nil, err
	}
	for _, file := range files {
		err := ForEachJSONL[SessionIndexEntry](file, func(entry SessionIndexEntry) error {
			if entry.ID != "" {
				ids[entry.ID] = struct{}{}
			}
			return nil
		})
		if err != nil {
			return nil, err
		}
	}
	return ids, nil
}

func relativizePath(root, path string) string {
	if path == "" {
		return ""
	}
	if root != "" && filepath.IsAbs(path) {
		if rel, err := filepath.Rel(root, path); err == nil && !strings.HasPrefix(rel, "..") {
			return filepath.ToSlash(rel)
		}
	}
	return filepath.ToSlash(path)
}

func resolveProjectPath(projectRoot, path string) string {
	if path == "" || filepath.IsAbs(path) || projectRoot == "" {
		return path
	}
	return filepath.Join(projectRoot, filepath.FromSlash(path))
}

func bodiesFromResultJSON(data []byte) (string, string) {
	var raw map[string]any
	if err := json.Unmarshal(data, &raw); err != nil {
		return "", ""
	}
	response := firstString(raw, "response", "output", "final_text", "finalText", "detail")
	stderr := firstString(raw, "stderr", "error")
	return response, stderr
}

func bodiesFromNativeLog(path string) (string, string) {
	f, err := os.Open(path)
	if err != nil {
		return "", ""
	}
	defer f.Close()
	var response, stderr string
	scanner := bufio.NewScanner(f)
	scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
	for scanner.Scan() {
		var raw map[string]any
		if err := json.Unmarshal(scanner.Bytes(), &raw); err != nil {
			continue
		}
		if s := firstNestedString(raw, []string{"data", "final_text"}, []string{"data", "finalText"}, []string{"final_text"}, []string{"finalText"}); s != "" {
			response = s
		}
		if s := firstNestedString(raw, []string{"data", "error"}, []string{"error"}, []string{"stderr"}); s != "" {
			stderr = s
		}
	}
	return response, stderr
}

func firstString(raw map[string]any, keys ...string) string {
	for _, key := range keys {
		if s, ok := raw[key].(string); ok && s != "" {
			return s
		}
	}
	return ""
}

func firstNestedString(raw map[string]any, paths ...[]string) string {
	for _, path := range paths {
		cur := any(raw)
		for _, key := range path {
			m, ok := cur.(map[string]any)
			if !ok {
				cur = nil
				break
			}
			cur = m[key]
		}
		if s, ok := cur.(string); ok && s != "" {
			return s
		}
	}
	return ""
}

import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

const SESSIONS_QUERY = gql`
	query AgentSessions($first: Int) {
		agentSessions(first: $first) {
			edges {
				node {
					id
					projectId
					beadId
					workerId
					harness
					model
					effort
					status
					startedAt
					endedAt
					durationMs
					cost
					tokens {
						prompt
						completion
						total
						cached
					}
					outcome
					detail
				}
				cursor
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
	}
`

export const SESSION_DETAIL_QUERY = gql`
	query AgentSessionDetail($id: ID!) {
		agentSession(id: $id) {
			id
			prompt
			response
			stderr
		}
	}
`

interface TokenUsage {
	prompt: number | null
	completion: number | null
	total: number | null
	cached: number | null
}

export interface SessionNode {
	id: string
	projectId: string
	beadId: string | null
	workerId: string | null
	harness: string
	model: string
	effort: string
	status: string
	startedAt: string
	endedAt: string | null
	durationMs: number
	cost: number | null
	tokens: TokenUsage | null
	outcome: string | null
	detail: string | null
	prompt?: string | null
	response?: string | null
	stderr?: string | null
}

interface SessionEdge {
	node: SessionNode
	cursor: string
}

interface SessionConnection {
	edges: SessionEdge[]
	pageInfo: { hasNextPage: boolean; endCursor: string | null }
	totalCount: number
}

interface SessionsResult {
	agentSessions: SessionConnection
}

export const load: PageLoad = async ({ params, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch)
	const data = await client.request<SessionsResult>(SESSIONS_QUERY, { first: 100 })
	const filteredEdges = data.agentSessions.edges.filter(
		(e) => e.node.projectId === params.projectId
	)
	return {
		nodeId: params.nodeId,
		projectId: params.projectId,
		sessions: {
			...data.agentSessions,
			edges: filteredEdges,
			totalCount: filteredEdges.length
		}
	}
}
<script lang="ts">
	import { createClient } from '$lib/gql/client';
	import { invalidateAll } from '$app/navigation';
	import { onMount } from 'svelte';
	import type { PageData } from './$types';
	import { SESSION_DETAIL_QUERY, type SessionNode } from './+page';

	let { data }: { data: PageData } = $props();

	// Track which sessions are expanded
	let expanded = $state<Set<string>>(new Set());
	let sessionBodies = $state<Record<string, Pick<SessionNode, 'prompt' | 'response' | 'stderr'>>>({});

	onMount(() => {
		const timer = window.setInterval(() => {
			void invalidateAll();
		}, 2000);
		return () => window.clearInterval(timer);
	});

	async function toggle(id: string) {
		const next = new Set(expanded);
		if (next.has(id)) {
			next.delete(id);
		} else {
			next.add(id);
			if (!sessionBodies[id]) {
				const client = createClient(fetch);
				const detail = await client.request<{ agentSession: SessionNode | null }>(
					SESSION_DETAIL_QUERY,
					{ id }
				);
				if (detail.agentSession) {
					sessionBodies = {
						...sessionBodies,
						[id]: {
							prompt: detail.agentSession.prompt,
							response: detail.agentSession.response,
							stderr: detail.agentSession.stderr
						}
					};
				}
			}
		}
		expanded = next;
	}

	const recordingGap = $derived.by(() => {
		const sorted = [...data.sessions.edges].sort(
			(a, b) => new Date(a.node.startedAt).getTime() - new Date(b.node.startedAt).getTime()
		);
		for (let i = 1; i < sorted.length; i++) {
			const prev = new Date(sorted[i - 1].node.startedAt);
			const next = new Date(sorted[i].node.startedAt);
			if (next.getTime() - prev.getTime() > 24 * 60 * 60 * 1000) {
				return `No sessions recorded between ${prev.toLocaleDateString()} and ${next.toLocaleDateString()}`;
			}
		}
		return null;
	});

	// Aggregate token summary
	const summary = $derived.by(() => {
		let totalCost = 0;
		let totalPrompt = 0;
		let totalCompletion = 0;
		let totalCached = 0;
		let totalTokens = 0;
		for (const edge of data.sessions.edges) {
			const s = edge.node;
			if (s.cost != null) totalCost += s.cost;
			if (s.tokens) {
				totalPrompt += s.tokens.prompt ?? 0;
				totalCompletion += s.tokens.completion ?? 0;
				totalCached += s.tokens.cached ?? 0;
				totalTokens += s.tokens.total ?? 0;
			}
		}
		const cacheRate = totalTokens > 0 ? Math.round((totalCached / totalTokens) * 100) : 0;
		return { totalCost, totalPrompt, totalCompletion, totalCached, totalTokens, cacheRate };
	});

	function fmtDuration(ms: number): string {
		if (ms < 1000) return `${ms}ms`;
		if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`;
		const m = Math.floor(ms / 60_000);
		const s = Math.floor((ms % 60_000) / 1000);
		return `${m}m ${s}s`;
	}

	function fmtDate(iso: string): string {
		return new Date(iso).toLocaleString();
	}

	function fmtCost(c: number | null): string {
		if (c == null) return '—';
		return `$${c.toFixed(4)}`;
	}

	function statusClass(status: string): string {
		switch (status) {
			case 'completed':
				return 'text-status-completed';
			case 'running':
				return 'text-status-running';
			case 'failed':
				return 'text-status-failed';
			default:
				return 'text-gray-500 dark:text-gray-400';
		}
	}

	function workersHref(): string {
		return `/nodes/${data.nodeId}/projects/${data.projectId}/workers`;
	}

	function workerHref(workerId: string): string {
		return `/nodes/${data.nodeId}/projects/${data.projectId}/workers/${workerId}`;
	}
</script>

