func TestAgentLogFormatElapsed(t *testing.T) {
	cases := []struct {
		d    time.Duration
		want string
	}{
		{30 * time.Second, "30s"},
		{90 * time.Second, "1m"},
		{90 * time.Minute, "1h"},
		{25 * time.Hour, "1d"},
		{0, "0s"},
		{-5 * time.Second, "0s"},
	}
	for _, tc := range cases {
