	deadline := time.Now().Add(2 * time.Second)
	for {
		rows, err := resolver.EfficacyRows(context.Background(), nil, nil, nil)
		if err != nil {
			t.Fatal(err)
		}
		for _, row := range rows {
			if row.RowKey == key && row.Attempts == 1 {
				return
			}
